  /* ════════════════════════════════════════════════════ */
  /* SLIDE 1 — COVER                                    */
  /* ════════════════════════════════════════════════════ */
  .slide-1 {
    background: linear-gradient(160deg, #0f172a 0%, #1a1a3e 50%, #0f172a 100%);
  }
  .slide-1 .slide-label { color: var(--accent-cyan); }
  .slide-1 .cover-emoji { font-size: 80px; margin-bottom: 32px; }
  .slide-1 .cover-title {
    font-size: 66px;
    font-weight: 800;
    line-height: 1.12;
    color: var(--text-primary);
    margin-bottom: 28px;
  }
  .slide-1 .cover-subtitle {
    font-size: 28px;
    font-weight: 500;
    line-height: 1.5;
    color: var(--text-secondary);
    margin-bottom: 40px;
  }
  .slide-1 .tags { display: flex; flex-wrap: wrap; gap: 10px; }
  .slide-1 .tag-blue { background: rgba(59,130,246,0.15); color: var(--accent-blue); border: 1px solid rgba(59,130,246,0.3); }
  .slide-1 .tag-cyan { background: rgba(6,182,212,0.15); color: var(--accent-cyan); border: 1px solid rgba(6,182,212,0.3); }
  .slide-1 .tag-green { background: rgba(16,185,129,0.15); color: var(--accent-green); border: 1px solid rgba(16,185,129,0.3); }
  .slide-1 .tag-amber { background: rgba(245,158,11,0.15); color: var(--accent-amber); border: 1px solid rgba(245,158,11,0.3); }
  .slide-1 .tag-purple { background: rgba(139,92,246,0.15); color: var(--accent-purple); border: 1px solid rgba(139,92,246,0.3); }
